/*
 * cos() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly cos  (test_cos_opt.elf)
 *   2. Linked with toolchain's default cos       (test_cos_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += cos(vx);
#else
    double r = cos(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* Representative 100-point test covering all input classes            */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    emit_u(0xfff0000000000000ULL);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* max positive subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (4) --- */
    emit(DBL_MIN);                  /* 2^-1022, smallest normal */
    emit(-DBL_MIN);
    emit(DBL_MAX);                  /* 0x7fefffffffffffff, largest normal */
    emit(-DBL_MAX);

    /* --- Section 4: Near 1.0 (8) --- */
    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0 */
    emit(1.0);
    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0 */
    emit_u(0x3fefffffffff0000ULL);  /* a few ULPs below 1.0 */
    emit_u(0x3ff0000000010000ULL);  /* a few ULPs above 1.0 */
    emit(-1.0);
    emit_u(0xbfefffffffffffffULL);  /* one ULP toward zero from -1.0 */
    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching points (6) --- */
    emit_u(0x3fe0000000000000ULL);  /* 0.5 */
    emit_u(0x3fdffffffffffffeULL);  /* one ULP below 0.5 */
    emit_u(0x3fe0000000000001ULL);  /* one ULP above 0.5 */
    emit_u(0x4000000000000000ULL);  /* 2.0 */
    emit_u(0x3fffffffffffffffULL);  /* one ULP below 2.0 */
    emit_u(0x4000000000000001ULL);  /* one ULP above 2.0 */

    /* --- Section 6: Pi-grid angles (14) --- */
    /* cos has known exact/near-exact values at multiples of pi/6, pi/4, etc. */
    emit(3.14159265358979323846 / 6.0);    /* pi/6:   cos = sqrt(3)/2 */
    emit(3.14159265358979323846 / 4.0);    /* pi/4:   cos = sqrt(2)/2 */
    emit(3.14159265358979323846 / 3.0);    /* pi/3:   cos = 0.5 */
    emit(3.14159265358979323846 / 2.0);    /* pi/2:   cos = 0 */
    emit(2.0 * 3.14159265358979323846 / 3.0);  /* 2pi/3:  cos = -0.5 */
    emit(3.0 * 3.14159265358979323846 / 4.0);  /* 3pi/4:  cos = -sqrt(2)/2 */
    emit(5.0 * 3.14159265358979323846 / 6.0);  /* 5pi/6:  cos = -sqrt(3)/2 */
    emit(3.14159265358979323846);               /* pi:     cos = -1 */
    emit(3.0 * 3.14159265358979323846 / 2.0);  /* 3pi/2:  cos = 0 */
    emit(2.0 * 3.14159265358979323846);         /* 2pi:    cos = 1 */
    emit(-3.14159265358979323846 / 4.0);        /* -pi/4 */
    emit(-3.14159265358979323846 / 2.0);        /* -pi/2:  cos = 0 */
    emit(-3.14159265358979323846);              /* -pi:    cos = -1 */
    emit(-2.0 * 3.14159265358979323846);        /* -2pi:   cos = 1 */

    /* --- Section 7: Argument reduction stress (8) --- */
    /* Large args where mantissa bits stress the range-reduction algorithm */
    emit(1.0e15);
    emit(1.0e16);
    emit(1.0e17);
    emit(-1.0e15);
    emit(-1.0e17);
    emit(1.23456789012345e15);              /* irrational large */
    emit_u(0x432921fb54442d18ULL);          /* 2^51*(pi/2): Payne-Hanek hard case */
    emit(1.0e20);

    /* --- Section 8: ULP neighbors of key trig boundaries (15) --- */
    /* Triplets around pi/2 */
    emit_u(0x3ff921fb54442d17ULL);  /* one ULP below pi/2 */
    emit_u(0x3ff921fb54442d18ULL);  /* pi/2 */
    emit_u(0x3ff921fb54442d19ULL);  /* one ULP above pi/2 */
    /* Triplets around pi */
    emit_u(0x400921fb54442d17ULL);  /* one ULP below pi */
    emit_u(0x400921fb54442d18ULL);  /* pi */
    emit_u(0x400921fb54442d19ULL);  /* one ULP above pi */
    /* Triplets around 3pi/2 */
    emit_u(0x4012d97c7f3321d1ULL);  /* one ULP below 3pi/2 */
    emit_u(0x4012d97c7f3321d2ULL);  /* 3pi/2 */
    emit_u(0x4012d97c7f3321d3ULL);  /* one ULP above 3pi/2 */
    /* Triplets around 2pi */
    emit_u(0x401921fb54442d17ULL);  /* one ULP below 2pi */
    emit_u(0x401921fb54442d18ULL);  /* 2pi */
    emit_u(0x401921fb54442d19ULL);  /* one ULP above 2pi */
    /* Triplets around -pi/2 */
    emit_u(0xbff921fb54442d17ULL);  /* one ULP below -pi/2 (toward zero) */
    emit_u(0xbff921fb54442d18ULL);  /* -pi/2 */
    emit_u(0xbff921fb54442d19ULL);  /* one ULP above -pi/2 (away from zero) */

    /* --- Section 9: Small-argument fast-path thresholds (8) --- */
    /* Many cos implementations use cos(x)~1 below a threshold */
    emit_u(0x3fb0000000000000ULL);   /* 2^-12: ~2.44e-4 */
    emit_u(0xbfb0000000000000ULL);   /* -2^-12 */
    emit_u(0x3e50000000000000ULL);   /* 2^-26: ~1.49e-8 */
    emit_u(0xbe50000000000000ULL);   /* -2^-26 */
    emit_u(0x3f80000000000000ULL);   /* 2^-7: ~7.81e-3 */
    emit_u(0xbf80000000000000ULL);   /* -2^-7 */
    emit_u(0x3f20000000000000ULL);   /* 2^-13: ~1.22e-4 */
    emit_u(0xbf20000000000000ULL);   /* -2^-13 */

    /* --- Section 10: Polynomial branch and hard reduction cases (24) --- */
    /* ULP neighbors of pi/8 (midpoint of primary polynomial interval) */
    emit_u(0x3fd921fb54442d17ULL);  /* one ULP below pi/8 */
    emit_u(0x3fd921fb54442d18ULL);  /* pi/8 */
    emit_u(0x3fd921fb54442d19ULL);  /* one ULP above pi/8 */
    /* ULP neighbors of pi/4 (polynomial switchover boundary) */
    emit_u(0x3fe921fb54442d17ULL);  /* one ULP below pi/4 */
    emit_u(0x3fe921fb54442d18ULL);  /* pi/4 */
    emit_u(0x3fe921fb54442d19ULL);  /* one ULP above pi/4 */
    /* 3pi/8 and -3pi/8 (exercises cos-path reconstruction) */
    emit(3.0 * 3.14159265358979323846 / 8.0);   /* 3pi/8 */
    emit(-3.0 * 3.14159265358979323846 / 8.0);  /* -3pi/8 */
    /* k*pi for k=3,4,5,10: cos near +/-1, tests periodic reduction */
    emit(3.0 * 3.14159265358979323846);          /* 3pi:  cos = -1 */
    emit(4.0 * 3.14159265358979323846);          /* 4pi:  cos = 1 */
    emit(5.0 * 3.14159265358979323846);          /* 5pi:  cos = -1 */
    emit(10.0 * 3.14159265358979323846);         /* 10pi: cos = 1 */
    /* Odd half-multiples: 5pi/2, 7pi/2, -5pi/2 (cos = 0 after reduction) */
    emit(5.0 * 3.14159265358979323846 / 2.0);    /* 5pi/2:  cos = 0 */
    emit(7.0 * 3.14159265358979323846 / 2.0);    /* 7pi/2:  cos = 0 */
    emit(-5.0 * 3.14159265358979323846 / 2.0);   /* -5pi/2: cos = 0 */
    /* Scaled pi/2 bit patterns at 2^23, 2^26 magnitude (range reduction stress) */
    emit_u(0x4169921fb54442d1ULL);  /* ~2^23 * pi/2: magnitude near 2^23 */
    emit_u(0x4189921fb54442d1ULL);  /* ~2^26 * pi/2: magnitude near 2^26 */
    /* Non-pi normals hitting mid-quadrant polynomial paths */
    emit(3.0);
    emit(-3.0);
    emit(1.0e10);
    emit(-1.0e10);
    /* Additional range-reduction hard cases near large multiples of pi */
    emit_u(0x4160000000000000ULL);  /* 8388608.0 = 2^23: mantissa boundary */
    emit_u(0x41a0000000000000ULL);  /* 2^27: further mantissa precision stress */
    emit_u(0xc160000000000000ULL);  /* -2^23 */
}

/* ------------------------------------------------------------------ */
/* Dense sweeps (accuracy path only)                                   */
/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* Sweep [0, 4*pi] and [-4*pi, 0] in 200 steps each */
static void test_sweep(void)
{
    double hi = 4.0 * 3.14159265358979323846;
    int nsteps = 200;
    double step = hi / (double)nsteps;

    /* [0, 4*pi] */
    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);

    /* [-4*pi, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (double)i * step);
}

/* Sample [0, pi/4] every 4503599627370496 ULP (~200 cases) */
static void test_exhaustive_small(void)
{
    uint64_t end = 0x3fe921fb54442d18ULL; /* pi/4 */
    for (uint64_t b = 0; b <= end; b += 4503599627370496ULL)
        emit_u(b);
}

/* Random sweep: 300 evenly spaced inputs */
static void test_random_300(void)
{
    double lo = -6.283185307179586;  /* -2*pi */
    double hi =  6.283185307179586;  /* +2*pi */
    int n = 300;
    for (int i = 0; i < n; i++) {
        double x = lo + (hi - lo) * (double)i / (double)(n - 1);
        emit(x);
    }
}
#endif

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
/*
 * Critical path for cos():
 *   __gf_dpreduct  (argument reduction)
 *   -> __gf_exmul  (extended-precision multiply)
 *   -> __gf_sigmax(__gf_dpcoscon, degree 5)  (polynomial kernel)
 *   -> __gf_exmul  (scale result)
 *
 * This path is taken when the reduced quadrant index q satisfies
 * (q-1)&2 == 0, i.e. q == 1 or q == 2.  x = 1.0 falls in quadrant 0.
 */
static void perf(double x)
{
    volatile double acc = 0.0;
    startPFM;
    for (int i = 0; i < 100; i++)
        acc += cos(x+i);
    stopPFM;
    readResult();
    printf("perf %016llx: %016llx\n",
           (unsigned long long)d2u(x),
           (unsigned long long)d2u((double)acc));
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
    perf(1.0); /* quadrant 0: hits cos-polynomial kernel path */
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
    test_random_300();
#endif
    return 0;
}
